Below is a complete, production-ready REST API for a simple task manager app using Node.js and Express. This API includes user authentication with JSON Web Tokens (JWT), user and project models, as well as task handling. 

Make sure to install the required dependencies first:
```sh
npm install express jsonwebtoken bcryptjs dotenv cors body-parser
```

Here's the complete code:

```javascript
// Import necessary modules
const express = require('express');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const cors = require('cors');
const bodyParser = require('body-parser');
const { Sequelize, DataTypes } = require('sequelize');

// Initialize app
const app = express();
app.use(cors());
app.use(bodyParser.json());

// Environment variables
require('dotenv').config();

// Database configuration
const sequelize = new Sequelize('database', 'username', 'password', {
  host: 'localhost',
  dialect: 'sqlite',
  logging: false,
  storage: 'task-manager.db'
});

// User model
const User = sequelize.define('User', {
  username: {
    type: DataTypes.STRING,
    unique: true,
    allowNull: false
  },
  password: {
    type: DataTypes.STRING,
    allowNull: false
  }
});

// Task model
const Task = sequelize.define('Task', {
  name: {
    type: DataTypes.STRING,
    allowNull: false
  },
  description: DataTypes.STRING,
  completed: {
    type: DataTypes.BOOLEAN,
    defaultValue: false
  }
});

// Project model
const Project = sequelize.define('Project', {
  name: {
    type: DataTypes.STRING,
    allowNull: false
  },
  description: DataTypes.TEXT
});

// Association
Task.belongsTo(Project);
Project.hasMany(Task);

// Middleware for JWT verification
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (token == null) return res.sendStatus(401);

  jwt.verify(token, process.env.ACCESS_TOKEN_SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// User registration
const registerUser = async (req, res) => {
  const { username, password } = req.body;
  try {
    const hashedPassword = await bcrypt.hash(password, 8);
    await User.create({ username, password: hashedPassword });
    res.status(201).send('User created');
  } catch (error) {
    res.status(400).send('Username already exists');
  }
};

// User login
const loginUser = async (req, res) => {
  const { username, password } = req.body;
  const user = await User.findOne({ where: { username } });

  if (!user) return res.status(400).send('User does not exist');

  const isPasswordValid = await bcrypt.compare(password, user.password);
  if (!isPasswordValid) return res.status(400).send('Invalid password');

  const token = jwt.sign({ username: user.username }, process.env.ACCESS_TOKEN_SECRET, {
    expiresIn: '30m'
  });

  res.status(200).json({ token });
};

// Create a project
const createProject = async (req, res) => {
  const { name, description } = req.body;
  try {
    await Project.create({ name, description });
    res.status(201).send('Project created');
  } catch (error) {
    res.status(400).send('Project with same name already exists');
  }
};

// Create a task
const createTask = async (req, res) => {
  const { name, description, project_id } = req.body;
  try {
    const task = await Task.create({ name, description });
    await Project.findByPk(project_id).then(project => project.addTask(task));
    res.status(201).send(task);
  } catch (error) {
    res.status(400).send('Task creation failed');
  }
};

// List all tasks for a specific project
const listTasks = async (req, res) => {
  const { project_id } = req.query;
  try {
    const tasks = await Project.findByPk(project_id).then(project => project.getTasks());
    res.status(200).json(tasks);
  } catch (error) {
    res.status(400).send('Project not found or no tasks');
  }
};

